{
  "description": "The quiz assesses knowledge of HTML5 semantic elements versus generic tags, testing both basic markup familiarity and deeper understanding of modern web standards. It is positioned as a moderate‑difficulty challenge with a light, encouraging tone that nudges learners to improve their semantic HTML usage. The style is informal and motivational, prompting participants to reflect on their skills and share results.",
  "topics": [
    "HTML5 semantic elements",
    "Difference between <div> and <span>",
    "Modern web markup best practices",
    "Accessibility considerations"
  ],
  "audience": "Front‑end developers, web designers, and students who have basic HTML experience and want to validate or deepen their understanding of HTML5 semantics."
}
